// @ts-nocheck
import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

/**
 * Phase 14 — Zero-Handshake Trust Manifest Endpoint
 *
 * Endpoint:
 * /.well-known/whenisdue-trust.json
 */

export const runtime = "nodejs";

function safeReadJson(absPath: string): any | null {
  try {
    if (!fs.existsSync(absPath)) return null;
    const raw = fs.readFileSync(absPath, "utf-8");
    const parsed = JSON.parse(raw);
    return parsed ?? null;
  } catch {
    return null;
  }
}

function isoNowUtc(): string {
  return new Date().toISOString();
}

export async function GET() {
  // 1) Prefer pre-built trust contract (CI-owned, signed, deterministic).
  const prebuiltPath = path.join(
    process.cwd(),
    "public",
    ".well-known",
    "whenisdue-trust.json"
  );
  const prebuilt = safeReadJson(prebuiltPath);
  if (prebuilt) {
    return NextResponse.json(prebuilt, {
      status: 200,
      headers: {
        "Content-Type": "application/json",
        "Cache-Control": "no-cache, must-revalidate"
      }
    });
  }

  // 2) Fallback: synthesize from other public artifacts (best-effort).
  const originPath = path.join(
    process.cwd(),
    "public",
    ".well-known",
    "whenisdue-origin.json"
  );
  const checkpointPath = path.join(
    process.cwd(),
    "public",
    ".well-known",
    "registry-checkpoint.json"
  );
  const sthPath = path.join(
    process.cwd(),
    "public",
    "transparency",
    "sth",
    "latest.json"
  );

  const origin = safeReadJson(originPath) || {};
  const checkpoint = safeReadJson(checkpointPath) || {};
  const sth = safeReadJson(sthPath) || {};

  const issuer = typeof origin.iss === "string" ? origin.iss : "https://whenisdue.com";
  const did = "did:web:whenisdue.com";

  // Prefer transparency STH root hash; fall back to registry checkpoint rootHash.
  const rootHash =
    (typeof sth.root_hash === "string" && sth.root_hash) ||
    (typeof sth.rootHash === "string" && sth.rootHash) ||
    (typeof checkpoint.rootHash === "string" && checkpoint.rootHash) ||
    null;

  // Prefer transparency STH tree size; fall back to checkpoint.treeSize.
  const treeSize =
    (Number.isFinite(sth.tree_size) ? sth.tree_size : null) ??
    (Number.isFinite(sth.treeSize) ? sth.treeSize : null) ??
    (Number.isFinite(checkpoint.treeSize) ? checkpoint.treeSize : null) ??
    null;

  const timestamp =
    (typeof sth.timestamp === "string" && sth.timestamp) ||
    (typeof checkpoint.generatedAt === "string" && checkpoint.generatedAt) ||
    isoNowUtc();

  const witnesses = {
    dns: typeof origin.dnsWitness === "string" ? origin.dnsWitness : null,
    github: typeof origin.githubWitness === "string" ? origin.githubWitness : null
  };

  const fallbackProof =
    origin.proof && typeof origin.proof === "object" ? origin.proof : null;

  const synthesized = {
    context: `${issuer}/v1/trust-contract`,
    id: did,
    issuer,
    registryId:
      typeof origin.registryId === "string"
        ? origin.registryId
        : "urn:whenisdue:registry:global",
    version:
      typeof checkpoint.version_id === "string"
        ? checkpoint.version_id
        : typeof checkpoint.version === "string"
          ? checkpoint.version
          : "registry-current",
    sth: {
      tree_size: treeSize,
      root_hash: rootHash,
      timestamp
    },
    witnesses,
    discovery: {
      llms: `${issuer}/llms.txt`,
      transparency: `${issuer}/transparency`,
      origin: `${issuer}/.well-known/whenisdue-origin.json`
    },
    proof:
      fallbackProof || {
        type: "DataIntegrityProof",
        cryptosuite: "eddsa-jcs-2022",
        verificationMethod: `${did}#key-1`,
        proofValue: null
      }
  };

  return NextResponse.json(synthesized, {
    status: 200,
    headers: {
      "Content-Type": "application/json",
      "Cache-Control": "no-cache, must-revalidate"
    }
  });
}